import Footer from '@/components/Footer.vue'
import { mapGetters } from 'vuex'

export default defineComponent({
	components :{
		MobileNavBar,
		NavBar,
		Footer
	},
	computed: {
		...mapGetters({
			projects: "projects"
		})
	}
})
