
import { defineComponent, PropType } from 'vue'
import { Project } from '@/models'
import TheCarousel from '../TheCarousel.vue';

export default defineComponent({
    components: {
		TheCarousel,
	},
    props: {
        project: {
            type: Object as PropType<Project>,
            required: true
        },
        right: {
            type: Boolean,
            required: false,
            default: false
        }
    },
})
